// test_harness.h - Minimal unit testing framework for GitSmarter
// Zero external dependencies, ~150 lines, CI-compatible exit codes
#pragma once

#include <cstdio>
#include <cstring>
#include <cstdint>

namespace Test {

// ============================================================================
// Test Registry
// ============================================================================

using TestFunc = void(*)();

struct TestEntry {
    const char* name;
    TestFunc func;
    const char* file;
    int line;
};

constexpr int MAX_TESTS = 1024;

static TestEntry g_tests[MAX_TESTS];
static int g_test_count = 0;

static int g_pass_count = 0;
static int g_fail_count = 0;
static int g_skip_count = 0;
static const char* g_current_test = nullptr;
static bool g_current_failed = false;

// Register a test at startup
inline int register_test(const char* name, TestFunc func, const char* file, int line) {
    if (g_test_count < MAX_TESTS) {
        g_tests[g_test_count++] = { name, func, file, line };
    }
    return g_test_count;
}

// ============================================================================
// Test Execution
// ============================================================================

inline void begin(const char* name) {
    g_current_test = name;
    g_current_failed = false;
}

inline void pass() {
    if (!g_current_failed) {
        g_pass_count++;
        printf("  [PASS] %s\n", g_current_test);
    }
}

inline void fail(const char* file, int line, const char* expr) {
    if (!g_current_failed) {
        g_current_failed = true;
        g_fail_count++;
    }
    printf("  [FAIL] %s\n    %s(%d): %s\n", g_current_test, file, line, expr);
}

inline void fail_msg(const char* file, int line, const char* msg) {
    if (!g_current_failed) {
        g_current_failed = true;
        g_fail_count++;
    }
    printf("  [FAIL] %s\n    %s(%d): %s\n", g_current_test, file, line, msg);
}

inline void skip(const char* reason) {
    g_skip_count++;
    printf("  [SKIP] %s - %s\n", g_current_test, reason);
}

// ============================================================================
// Assertion Macros
// ============================================================================

#define TEST_ASSERT(expr) \
    do { if (!(expr)) { Test::fail(__FILE__, __LINE__, #expr); return; } } while(0)

#define TEST_ASSERT_TRUE(expr) TEST_ASSERT(expr)

#define TEST_ASSERT_FALSE(expr) \
    do { if (expr) { Test::fail(__FILE__, __LINE__, "!" #expr); return; } } while(0)

#define TEST_ASSERT_EQ(a, b) \
    do { if ((a) != (b)) { Test::fail(__FILE__, __LINE__, #a " == " #b); return; } } while(0)

#define TEST_ASSERT_NE(a, b) \
    do { if ((a) == (b)) { Test::fail(__FILE__, __LINE__, #a " != " #b); return; } } while(0)

#define TEST_ASSERT_STREQ(a, b) \
    do { if (strcmp((a), (b)) != 0) { \
        char _buf[256]; \
        snprintf(_buf, sizeof(_buf), "\"%s\" == \"%s\"", (a), (b)); \
        Test::fail_msg(__FILE__, __LINE__, _buf); return; \
    } } while(0)

#define TEST_ASSERT_STRNE(a, b) \
    do { if (strcmp((a), (b)) == 0) { Test::fail(__FILE__, __LINE__, #a " != " #b); return; } } while(0)

#define TEST_ASSERT_MEMEQ(a, b, n) \
    do { if (memcmp((a), (b), (n)) != 0) { Test::fail(__FILE__, __LINE__, #a " == " #b " (memcmp)"); return; } } while(0)

#define TEST_ASSERT_NULL(ptr) \
    do { if ((ptr) != nullptr) { Test::fail(__FILE__, __LINE__, #ptr " == nullptr"); return; } } while(0)

#define TEST_ASSERT_NOT_NULL(ptr) \
    do { if ((ptr) == nullptr) { Test::fail(__FILE__, __LINE__, #ptr " != nullptr"); return; } } while(0)

#define TEST_SKIP(reason) \
    do { Test::skip(reason); return; } while(0)

// ============================================================================
// Test Registration Macro
// ============================================================================

#define TEST(name) \
    static void test_##name(); \
    static int _test_reg_##name = Test::register_test(#name, test_##name, __FILE__, __LINE__); \
    static void test_##name()

// ============================================================================
// Test Runner
// ============================================================================

inline bool matches_filter(const char* name, const char* filter) {
    if (!filter || filter[0] == '\0') return true;
    return strstr(name, filter) != nullptr;
}

inline int run_all_tests(const char* filter = nullptr) {
    printf("\n========================================\n");
    printf("GitSmarter Unit Tests\n");
    printf("========================================\n\n");

    if (filter && filter[0] != '\0') {
        printf("Filter: %s\n\n", filter);
    }

    int ran = 0;
    for (int i = 0; i < g_test_count; i++) {
        if (matches_filter(g_tests[i].name, filter)) {
            begin(g_tests[i].name);
            g_tests[i].func();
            if (!g_current_failed) {
                pass();
            }
            ran++;
        }
    }

    printf("\n========================================\n");
    printf("Results: %d passed, %d failed, %d skipped (of %d registered, %d ran)\n",
           g_pass_count, g_fail_count, g_skip_count, g_test_count, ran);
    printf("========================================\n\n");

    return g_fail_count > 0 ? 1 : 0;
}

} // namespace Test
